mapper.select:
SELECT L.id, L.userId, date_format(L.createTime, '%Y-%m-%d %H:%i:%s') as createTime, L.state, L.check, u.nickname, u.phone, s.storeName FROM user_token_login_logs as L LEFT JOIN user_info as u on u.userId = L.userId LEFT JOIN device as d on d.proxyId = L.userId LEFT JOIN store as s on s.storeId = d.storeId WHERE L.state = 1
and u.phone = #{phone}
and d.storeId = #{store_id}
AND d.storeId in (${storeIds})
ORDER BY L.id desc
limit #{offset}, #{limit}

SELECT count(*)
FROM user_token_login_logs
where state = 1

    and u.phone = #{phone}


    and d.storeId = #{store_id}

    
        AND d.storeId in (${storeIds})
    
ORDER BY L.id desc

    limit #{offset}, #{limit}
